1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote — base premiums and edge cases", () => {
6	    it("empty item list → premium 5 G (only processing fee)", () => {
7	      const result = runScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote", items: [] }],
10	      });
11	      expect(result).toEqual({ results: [{ premium: 5 }] });
12	    });
13	    it.todo("single sword (no modifiers, no first-insurance, no loyalty) → 100 G base + 5 G fee");
14	    it.todo("single amulet base premium 60 G + 5 G fee");
15	    it.todo("single staff base premium 80 G + 5 G fee");
16	    it.todo("single potion base premium 40 G + 5 G fee");
17	  });
18	
19	  describe("Quote — component blocks", () => {
20	    it.todo("2 runes → 50 G base premium (+ fee)");
21	    it.todo("3 runes → 60 G base premium (block applies)");
22	    it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
23	    it.todo("7 runes → 175 G base premium (no block beyond exactly 3)");
24	    it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
25	    it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
26	  });
27	
28	  describe("Quote — premium modifiers", () => {
29	    it.todo("cursed sword adds 50% of cursed item's base premium (cursed sword → 100 + 50 + fee)");
30	    it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge to that item");
31	    it.todo("sword with enchantment 4 → no high-enchantment surcharge");
32	    it.todo("cursed sword with enchantment 5 → both surcharges apply");
33	    it.todo("long-standing customer (≥ 2 years) → 20% loyalty discount on policy base");
34	    it.todo("customer with exactly 2 years → loyalty discount applies");
35	    it.todo("first insurance carries 10% initial assessment surcharge on policy base");
36	    it.todo("follow-up contract (after first) receives 15% discount on policy base");
37	    it.todo("multi-item: cursed sword + plain amulet → base 160, +50 curse = 210 before fee");
38	  });
39	
40	  describe("Quote — rounding", () => {
41	    it.todo("premium 197.5 G → final premium 198 G (rounded up in MHPCO's favor)");
42	  });
43	
44	  describe("Quote — integration examples", () => {
45	    it.todo("newcomer (0 years) with cursed sword (steel, ench 3) → premium 165 G");
46	    it.todo("long-standing (3 years) 2nd quote, cursed sword (steel, ench 7) → premium 160 G");
47	  });
48	
49	  describe("Quote — errors", () => {
50	    it.todo("unknown item type (e.g. broomstick) → throws / scenario rejected");
51	  });
52	
53	  describe("Claim — standard reimbursement", () => {
54	    it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (− 100 deductible)");
55	    it.todo("damage to a rune (insurance 250 G), damage 200 G → payout 100 G (− 100 deductible)");
56	  });
57	
58	  describe("Claim — special clauses", () => {
59	    it.todo("high-enchantment item (ench ≥ 8): 50% of damage, then deductible");
60	    it.todo("dragon-material item: full reimbursement, then deductible");
61	    it.todo("dragon sword, ench 9, damage 1000 → 400 (50% rule wins; 500 − 100)");
62	    it.todo("dragon sword, ench 5, damage 800 → 700 (dragon only; 800 − 100)");
63	    it.todo("steel sword, ench 9, damage 1000 → 400 (50% then deductible)");
64	    it.todo("dragon sword, ench 8, damage 1000 → 400 (high-ench applies, then deductible)");
65	  });
66	
67	  describe("Claim — deductible per event/item", () => {
68	    it.todo("dragon attack on sword (500) and amulet (300) → payout 600 (deductible per item)");
69	  });
70	
71	  describe("Claim — multiple items of same type", () => {
72	    it.todo("policy with two swords → insurance sum 2000, cap 4000");
73	    it.todo("damages array with two sword entries → each treated as separate damage with own deductible");
74	    it.todo("damages array has more entries of a type than the policy covers → claim rejected");
75	  });
76	
77	  describe("Claim — cap exhaustion", () => {
78	    it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
79	    it.todo("cursed sword (premium with modifiers 165 G) → cap based on insurance value (2000)");
80	    it.todo("sword + 3 runes (block) → insurance sum 1750 G; block does not affect cap");
81	    it.todo("sword cap 2000; claim 1500 → payout 1400, remaining 600");
82	    it.todo("after first 1400 claim, second claim 1500 → payout 600, remaining 0");
83	  });
84	
85	  describe("Claim — payout rounding", () => {
86	    it.todo("payout calculation 350.5 G → final payout 350 G (rounded down in MHPCO's favor)");
87	  });
88	
89	  describe("Claim — errors", () => {
90	    it.todo("damage references item not in policy (e.g. amulet damage on sword-only policy) → rejected");
91	    it.todo("damage with negative amount → rejected");
92	  });
93	});
